import pika
import subprocess
import sys

def callback(ch, method, properties, body):
    try:
        command = body.decode('utf-8')
        print(f" [x] Received and executing: '{command}'")

        # Execute the command
        # !!! WARNING: Executing arbitrary commands from an external source is a HUGE security risk.
        # Ensure that inputs are sanitized and restricted if this is exposed to untrusted sources.
        result = subprocess.run(command, shell=True, capture_output=True, text=True, check=False)

        print(f" [x] Command '{command}' finished.")
        if result.returncode == 0:
            print(f"     STDOUT:\n{result.stdout}")
        else:
            print(f"     STDERR (Exit Code {result.returncode}):\n{result.stderr}")
            if result.stdout:
                print(f"     STDOUT (despite error):\n{result.stdout}")

    except Exception as e:
        print(f" [!] Error processing message: {e}")
        # Optionally, you might want to NACK the message if processing failed
        # ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
    finally:
        ch.basic_ack(delivery_tag=method.delivery_tag)

def main():
    connection = None
    try:
        # Connect to RabbitMQ
        # Replace 'localhost' with your RabbitMQ server address if it's not local
        connection = pika.BlockingConnection(pika.ConnectionParameters(host='localhost'))
        channel = connection.channel()

        # Declare a queue named 'task_queue'
        # The 'durable=True' argument makes sure that the queue will survive a RabbitMQ restart
        channel.queue_declare(queue='task_queue', durable=True)

        print(' [*] Waiting for messages. To exit press CTRL+C')

        # Set prefetch_count to 1 to ensure that a worker only gets one message at a time
        # This prevents a worker from being overloaded and ensures messages are only delivered
        # after the previous one has been acknowledged.
        channel.basic_qos(prefetch_count=1)

        # Start consuming messages
        channel.basic_consume(queue='task_queue', on_message_callback=callback)

        channel.start_consuming()

    except pika.exceptions.AMQPConnectionError as e:
        print(f"Failed to connect to RabbitMQ: {e}")
        print("Please ensure RabbitMQ server is running and accessible at 'localhost'.")
        sys.exit(1)
    except KeyboardInterrupt:
        print(' [*] Exiting consumer.')
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
    finally:
        if connection and not connection.is_closed:
            connection.close()
            print(' [*] RabbitMQ connection closed.')

if __name__ == '__main__':
    main()